.darma-loader-uiverse-bicycle-blueprint {
  display: block;
  width: 150px;
  height: auto;
}

.darma-loader-uiverse-bicycle-blueprint__body,
.darma-loader-uiverse-bicycle-blueprint__front,
.darma-loader-uiverse-bicycle-blueprint__handlebars,
.darma-loader-uiverse-bicycle-blueprint__pedals,
.darma-loader-uiverse-bicycle-blueprint__pedals-spin,
.darma-loader-uiverse-bicycle-blueprint__seat,
.darma-loader-uiverse-bicycle-blueprint__spokes,
.darma-loader-uiverse-bicycle-blueprint__spokes-spin,
.darma-loader-uiverse-bicycle-blueprint__tire {
animation: darma-loader-uiverse-bicycle-blueprint-bikeBody 3s ease-in-out infinite;
stroke: var(--primary);
transition: stroke var(--trans-dur);
}

.darma-loader-uiverse-bicycle-blueprint__front {
animation-name: darma-loader-uiverse-bicycle-blueprint-bikeFront;
}

.darma-loader-uiverse-bicycle-blueprint__handlebars {
animation-name: darma-loader-uiverse-bicycle-blueprint-bikeHandlebars;
}

.darma-loader-uiverse-bicycle-blueprint__pedals {
animation-name: darma-loader-uiverse-bicycle-blueprint-bikePedals;
}

.darma-loader-uiverse-bicycle-blueprint__pedals-spin {
animation-name: darma-loader-uiverse-bicycle-blueprint-bikePedalsSpin;
}

.darma-loader-uiverse-bicycle-blueprint__seat {
animation-name: darma-loader-uiverse-bicycle-blueprint-bikeSeat;
}

.darma-loader-uiverse-bicycle-blueprint__spokes,
.darma-loader-uiverse-bicycle-blueprint__tire {
stroke: currentColor;
}

.darma-loader-uiverse-bicycle-blueprint__spokes {
animation-name: darma-loader-uiverse-bicycle-blueprint-bikeSpokes;
}

.darma-loader-uiverse-bicycle-blueprint__spokes-spin {
animation-name: darma-loader-uiverse-bicycle-blueprint-bikeSpokesSpin;
}

.darma-loader-uiverse-bicycle-blueprint__tire {
animation-name: darma-loader-uiverse-bicycle-blueprint-bikeTire;
}

/* Dark theme */

/* Animations */
@keyframes darma-loader-uiverse-bicycle-blueprint-bikeBody {
from {
stroke-dashoffset: 79;
}

33%,
67% {
stroke-dashoffset: 0;
}

to {
stroke-dashoffset: -79;
}
}

@keyframes darma-loader-uiverse-bicycle-blueprint-bikeFront {
from {
stroke-dashoffset: 19;
}

33%,
67% {
stroke-dashoffset: 0;
}

to {
stroke-dashoffset: -19;
}
}

@keyframes darma-loader-uiverse-bicycle-blueprint-bikeHandlebars {
from {
stroke-dashoffset: 10;
}

33%,
67% {
stroke-dashoffset: 0;
}

to {
stroke-dashoffset: -10;
}
}

@keyframes darma-loader-uiverse-bicycle-blueprint-bikePedals {
from {
animation-timing-function: ease-in;
stroke-dashoffset: -25.133;
}

33%,
67% {
animation-timing-function: ease-out;
stroke-dashoffset: -21.991;
}

to {
stroke-dashoffset: -25.133;
}
}

@keyframes darma-loader-uiverse-bicycle-blueprint-bikePedalsSpin {
from {
transform: rotate(0.1875turn);
}

to {
transform: rotate(3.1875turn);
}
}

@keyframes darma-loader-uiverse-bicycle-blueprint-bikeSeat {
from {
stroke-dashoffset: 5;
}

33%,
67% {
stroke-dashoffset: 0;
}

to {
stroke-dashoffset: -5;
}
}

@keyframes darma-loader-uiverse-bicycle-blueprint-bikeSpokes {
from {
animation-timing-function: ease-in;
stroke-dashoffset: -31.416;
}

33%,
67% {
animation-timing-function: ease-out;
stroke-dashoffset: -23.562;
}

to {
stroke-dashoffset: -31.416;
}
}

@keyframes darma-loader-uiverse-bicycle-blueprint-bikeSpokesSpin {
from {
transform: rotate(0);
}

to {
transform: rotate(3turn);
}
}

@keyframes darma-loader-uiverse-bicycle-blueprint-bikeTire {
from {
animation-timing-function: ease-in;
stroke-dashoffset: 56.549;
transform: rotate(0);
}

33% {
stroke-dashoffset: 0;
transform: rotate(0.33turn);
}

67% {
animation-timing-function: ease-out;
stroke-dashoffset: 0;
transform: rotate(0.67turn);
}

to {
stroke-dashoffset: -56.549;
transform: rotate(1turn);
}
}

